const body = $input.first().json.body || $input.first().json;

const rawPdf = (body.pdfBase64 || '').replace(/^data:[^;]+;base64,/, '');
const closurePdfFileName = body.workOrderId + '-CLOSED.pdf';

return [{
  json: {
    workOrderId: body.workOrderId,
    closedAt: body.closedAt,
    techName: body.techName,
    completionNotes: body.completionNotes,
    partsUsed: body.partsUsed || '',
    status: body.status,
    completionPhoto: body.completionPhoto || null,
    completionPhotoName: body.completionPhotoName || null,
    rawPdf,
    closurePdfFileName
  }
}];

const allRows = $input.all();
const prepData = $('Prep').first().json;
const workOrderId = prepData.workOrderId;

const match = allRows.find(item => item.json['Work Order ID'] === workOrderId);

if (!match) {
  return [{ json: { found: false, workOrderId } }];
}

return [{
  json: {
    found: true,
    ...prepData,
    locationGroup: match.json['Organization'],
    locationSub: match.json['Location']
  }
}];

const group = $json.locationGroup || '';
const sub   = $json.locationSub   || '';

const folderMap = {
  'Burroughs Restaurant Group': {
    'Collierville':  '180VIqckCkzbfTphClhiBdSXYDqKwc1-R',
    'Dexter':        '16sPwGAtuRIMVm_4338eo-ofU9g6oKJ1R',
    'Olive Branch':  '11lIU785alqHXpd31_YJWoSojcAz_vb0y',
    'Oxford':        '1CeZ8l73tVOhbvwykk3FnjpuGs0b1cuu7',
    'Whitehaven':    '1QkrW0-ervpfCIdMV4n7ZOz7NGD7P9i4u',
    '_group':        '1rsniXvtldFG-03TbWSu9QtsC792eoBWF'
  },
  'First Choice': {
    'Main Office':   '1P-h3MjK4orxrkhVBgiH8owR-Z1ua2nGj',
    'Warehouse':     '1TbJTEpeLyriGirFDSPw2-Pzws5jBnRH8',
    '_group':        '1Jhju0T0kEgkvdwXm9AFa0cJSqSqMt_bn'
  },
  'R.S. Lewis and Sons Funeral Home': {
    'Austin Peay':   '1k1J55XZXDyDKwc0JzvldgPAo4bFU6VUY',
    'Vance Avenue':  '1KkXJw-Llr47M_S7eZ_eWjju0Ui5pjHTT',
    'Walnut Grove':  '1K9D8cK5yibzPw3lXU99TEC-iGIU9hyLs',
    '_group':        '1yWoGnZ3qY6XiSfq74IITGlJxkjJ7juGJ'
  },
  'Misc. Facilities': {
    'Location #1':   '1EBeEL4pgYHEe-Cf7P3gQjxdIOZBn7RGg',
    'Location #2':   '1VfuIUglIWBvbn3m7_tBW0yYuqJ--95Mf',
    'Location #3':   '18UhfvUCfdJRz2XnVoINbouACakyN3ptx',
    'Location #4':   '1pfoBNYSasys9_vOBEntg4sCbkX3gfphr',
    'Location #5':   '1ilVs6ysHMFLwV3Cnm-EWN7UgtdOZAY3U',
    '_group':        '1nFOXhx_VLUnJ8XJWoSvQaZ6oduU3j_iK'
  }
};

const sheetTabMap = {
  'Burroughs Restaurant Group':       'BRG',
  'First Choice':                     'FC',
  'R.S. Lewis and Sons Funeral Home': 'RSL',
  'Misc. Facilities':                 'Misc'
};

const groupMap  = folderMap[group] || {};
const folderId  = groupMap[sub] || groupMap['_group'] || '1wJup8vKzYSL-sEnV_ZkEaijfmRbur1Ja';
const sheetTab  = sheetTabMap[group] || 'Misc';

return [{ json: { ...$json, driveFolderId: folderId, sheetTab } }];

const data = $json;
const items = [];

// Always create closure PDF binary
items.push({
  json: {
    fileType: 'closurePdf',
    fileName: data.closurePdfFileName,
    driveFolderId: data.driveFolderId
  },
  binary: {
    data: {
      data: data.rawPdf,
      mimeType: 'application/pdf',
      fileName: data.closurePdfFileName,
      fileExtension: 'pdf'
    }
  }
});

// Optionally create completion photo binary
if (data.completionPhoto) {
  const rawPhoto = (data.completionPhoto).replace(/^data:[^;]+;base64,/, '');
  const photoFileName = data.workOrderId + '-completion.jpg';
  items.push({
    json: {
      fileType: 'completionPhoto',
      fileName: photoFileName,
      driveFolderId: data.driveFolderId
    },
    binary: {
      data: {
        data: rawPhoto,
        mimeType: 'image/jpeg',
        fileName: photoFileName,
        fileExtension: 'jpg'
      }
    }
  });
}

return items;

const uploadResults = $('Upload to Drive').all();
const originalData = $('Resolve Drive Folder').first().json;

let closurePdfUrl = '';
let completionPhotoUrl = '';

for (let i = 0; i < uploadResults.length; i++) {
  const upload = uploadResults[i].json;
  const link = upload.webViewLink || upload.webContentLink || '';
  const binaryInfo = $('Create Closure Binaries').all()[i];
  const fileType = binaryInfo ? binaryInfo.json.fileType : (i === 0 ? 'closurePdf' : 'completionPhoto');

  if (fileType === 'closurePdf') {
    closurePdfUrl = link;
  } else if (fileType === 'completionPhoto') {
    completionPhotoUrl = link;
  }
}

const emailHtml = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto"><div style="background:#1a5276;color:#fff;padding:20px;text-align:center"><h1 style="margin:0">First Choice Facilities</h1><p style="margin:5px 0 0">Work Order Closure Confirmation</p></div><div style="padding:20px;border:1px solid #ddd"><h2 style="color:#1a5276">Work Order ${originalData.workOrderId} &mdash; ${originalData.status}</h2><table style="width:100%;border-collapse:collapse"><tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold;width:40%">Technician:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.techName}</td></tr><tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold">Closed At:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.closedAt}</td></tr><tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold">Status:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.status}</td></tr><tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold">Completion Notes:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.completionNotes}</td></tr><tr><td style="padding:8px;border-bottom:1px solid #eee;font-weight:bold">Parts Used:</td><td style="padding:8px;border-bottom:1px solid #eee">${originalData.partsUsed || 'None'}</td></tr></table><p style="margin-top:20px"><a href="${closurePdfUrl}" style="background:#1a5276;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px">View Closure PDF in Drive</a></p></div><div style="background:#f5f5f5;padding:10px;text-align:center;font-size:12px;color:#666">First Choice Facilities &mdash; Automated Notification</div></div>`;

const emailSubject = `Work Order ${originalData.workOrderId} \u2014 ${originalData.status} by ${originalData.techName}`;

const closurePdfBinary = $('Create Closure Binaries').first().binary.data;

return [{
  json: {
    workOrderId: originalData.workOrderId,
    status: originalData.status,
    techName: originalData.techName,
    closedAt: originalData.closedAt,
    completionNotes: originalData.completionNotes,
    partsUsed: originalData.partsUsed || '',
    completionPhotoUrl,
    closurePdfUrl,
    sheetTab: originalData.sheetTab,
    locationGroup: originalData.locationGroup,
    locationSub: originalData.locationSub,
    emailHtml,
    emailSubject
  },
  binary: {
    pdf: closurePdfBinary
  }
}];
